function _removeFacet(address facet_, bytes4[] memory selectors_) internal virtual {
    _checkIfFacetIsValid(facet_, selectors_);

    DStorage storage _ds = _getDiamondStorage();

    for (uint256 i = 0; i < selectors_.length; ++i) {
        if (_ds.selectorToFacet[selectors_[i]] != facet_)
            revert SelectorFromAnotherFacet(selectors_[i]);

        _ds.selectorToFacet[selectors_[i]] = address(0);
        _ds.facetToSelectors[facet_].remove(bytes32(selectors_[i]));
    }

    if (_ds.facetToSelectors[facet_].length() == 0) {
        _ds.facets.remove(facet_);
    }
}

function fromBytes(bytes memory bytes_) internal view returns (uint512 u512_) {
    unchecked {
        assert(bytes_.length < 65);

        u512_ = uint512.wrap(_allocate(_UINT512_ALLOCATION));

        assembly {
            mstore(u512_, 0)
            mstore(add(u512_, 0x20), 0)

            let size_ := mload(bytes_)
            pop(
                staticcall(
                    gas(),
                    0x4,
                    add(bytes_, 0x20),
                    size_,
                    add(u512_, sub(0x40, size_)),
                    size_
                )
            )
        }
    }
}

function _redadd(call512 call_, uint512 a_, uint512 b_, uint512 m_, uint512 r_) private pure {
    unchecked {
        uint512 buffer_ = _buffer(call_);
        bool overflowed_;

        assembly {
            let aWord_ := mload(add(a_, 0x20))
            let sum_ := add(aWord_, mload(add(b_, 0x20)))

            mstore(add(buffer_, 0x20), sum_)

            sum_ := gt(aWord_, sum_)
            sum_ := add(sum_, add(mload(a_), mload(b_)))

            mstore(buffer_, sum_)
            overflowed_ := gt(mload(a_), sum_)
        }

        if (overflowed_ || cmp(buffer_, m_) >= 0) {
            _sub(buffer_, m_, r_);
            return;
        }

        assign(buffer_, r_);
    }
}

function _mul(uint512 a_, uint512 b_, uint512 r_) private pure {
    unchecked {
        assembly {
            let a0_ := mload(a_)
            let a1_ := mload(add(a_, 0x20))
            let b0_ := mload(b_)
            let b1_ := mload(add(b_, 0x20))

            let mm_ := mulmod(
                a1_,
                b1_,
                0xffffffffffffffffffffffffffffffffffffffffffffffffffffffffffffffff
            )
            let c3_ := mul(a1_, b1_)
            let c2_ := sub(sub(mm_, c3_), lt(mm_, c3_))

            c2_ := add(c2_, mul(a0_, b1_))
            c2_ := add(c2_, mul(a1_, b0_))

            mstore(add(r_, 0x20), c3_)
            mstore(r_, c2_)
        }
    }
}

function _jDouble(
    uint256 jx1_,
    uint256 jy1_,
    uint256 jz1_,
    uint256 p_,
    uint256 a_
) private pure returns (uint256 jx2_, uint256 jy2_, uint256 jz2_) {
    assembly ("memory-safe") {
        let yy_ := mulmod(jy1_, jy1_, p_)
        let zz_ := mulmod(jz1_, jz1_, p_)
        let m_ := addmod(
            mulmod(3, mulmod(jx1_, jx1_, p_), p_),
            mulmod(a_, mulmod(zz_, zz_, p_), p_),
            p_
        )
        let s_ := mulmod(4, mulmod(jx1_, yy_, p_), p_)

        jx2_ := addmod(mulmod(m_, m_, p_), sub(p_, mulmod(2, s_, p_)), p_)
        jy2_ := addmod(
            mulmod(m_, addmod(s_, sub(p_, jx2_), p_), p_),
            sub(p_, mulmod(8, mulmod(yy_, yy_, p_), p_)),
            p_
        )
        jz2_ := mulmod(2, mulmod(jy1_, jz1_, p_), p_)
    }
}

function _isOnCurve(
    call512 call_,
    uint512 p_,
    uint512 a_,
    uint512 b_,
    uint512 x_,
    uint512 y_
) private view returns (bool) {
    unchecked {
        if (U512.eqU256(x_, 0) || U512.eq(x_, p_) || U512.eqU256(y_, 0) || U512.eq(y_, p_)) {
            return false;
        }

        uint512 lhs_ = U512.modexpU256(call_, y_, 2, p_);
        uint512 rhs_ = U512.modexpU256(call_, x_, 3, p_);

        if (!U512.eqU256(a_, 0)) {
            rhs_ = U512.redadd(call_, rhs_, U512.modmul(call_, x_, a_, p_), p_); // x^3 + a*x
        }

        if (!U512.eqU256(b_, 0)) {
            rhs_ = U512.redadd(call_, rhs_, b_, p_); // x^3 + a*x + b
        }

        return U512.eq(lhs_, rhs_);
    }
}

function _mgf(
    Parameters memory params_,
    bytes memory message_,
    uint256 maskLen_
) private pure returns (bytes memory res_) {
    unchecked {
        uint256 hashLength_ = params_.hashLength;

        bytes memory cnt_ = new bytes(4);

        assert(maskLen_ <= (2 ** 32) * hashLength_);

        for (uint256 i = 0; i < (maskLen_ + hashLength_ - 1) / hashLength_; ++i) {
            cnt_[0] = bytes1(uint8((i >> 24) & 255));
            cnt_[1] = bytes1(uint8((i >> 16) & 255));
            cnt_[2] = bytes1(uint8((i >> 8) & 255));
            cnt_[3] = bytes1(uint8(i & 255));

            bytes memory hashedResInter_ = params_.hasher(abi.encodePacked(message_, cnt_));

            res_ = abi.encodePacked(res_, hashedResInter_);
        }

        assembly {
            mstore(res_, maskLen_)
        }
    }
}

function _updateMerkleHashes(IndexedMT storage tree, uint256 leafIndex_) private {
    uint256 levelsCount_ = tree.levelsCount;
    uint256 levelIndex_ = leafIndex_;

    HashFunctions memory hashFunctions_ = _getHashFunctions(tree);

    for (uint256 i = 0; i < levelsCount_; i++) {
        bytes32 currentLevelNodeHash_;

        if (i == LEAVES_LEVEL) {
            LeafData memory leafData_ = _getLeafData(tree, levelIndex_);

            currentLevelNodeHash_ = _hashLeaf(
                levelIndex_,
                leafData_.value,
                leafData_.nextLeafIndex,
                true,
                hashFunctions_.hash4
            );
        } else {
            currentLevelNodeHash_ = _calculateNodeHash(tree, levelIndex_, i, hashFunctions_);
        }

        tree.nodes[i][levelIndex_] = currentLevelNodeHash_;

        levelIndex_ /= 2;
    }
}

function _reverseUint128(uint128 input_) private pure returns (uint128 result_) {
    unchecked {
        uint128 mask0_ = 0x10000000000000001 *
            (~uint128((input_ == uint128(0)).toUint()) >> 96);

        uint128 mask1_ = mask0_ ^ (mask0_ << 16);
        uint128 mask2_ = mask1_ ^ (mask1_ << 8);

        result_ = (mask2_ & (input_ >> 8)) | ((mask2_ & input_) << 8);
        result_ = (mask1_ & (result_ >> 16)) | ((mask1_ & result_) << 16);
        result_ = (mask0_ & (result_ >> 32)) | ((mask0_ & result_) << 32);
        result_ = (result_ >> 64) | (result_ << 64);
    }
}

function mulDiv18(uint256 x, uint256 y) pure returns (uint256 result) {
    uint256 prod0;
    uint256 prod1;
    assembly ("memory-safe") {
        let mm := mulmod(x, y, not(0))
        prod0 := mul(x, y)
        prod1 := sub(sub(mm, prod0), lt(mm, prod0))
    }

    if (prod1 == 0) {
        unchecked {
            return prod0 / UNIT;
        }
    }

    if (prod1 >= UNIT) {
        revert PRBMath_MulDiv18_Overflow(x, y);
    }

    uint256 remainder;
    assembly ("memory-safe") {
        remainder := mulmod(x, y, UNIT)
        result := mul(
            or(
                div(sub(prod0, remainder), UNIT_LPOTD),
                mul(sub(prod1, gt(remainder, prod0)), add(div(sub(0, UNIT_LPOTD), UNIT_LPOTD), 1))
            ),
            UNIT_INVERSE
        )
    }
}

function ceil(SD59x18 x) pure returns (SD59x18 result) {
    int256 xInt = x.unwrap();
    if (xInt > uMAX_WHOLE_SD59x18) {
        revert Errors.PRBMath_SD59x18_Ceil_Overflow(x);
    }

    int256 remainder = xInt % uUNIT;
    if (remainder == 0) {
        result = x;
    } else {
        unchecked {
            // Solidity uses C fmod style, which returns a modulus with the same sign as x.
            int256 resultInt = xInt - remainder;
            if (xInt > 0) {
                resultInt += uUNIT;
            }
            result = wrap(resultInt);
        }
    }
}

function floor(SD59x18 x) pure returns (SD59x18 result) {
    int256 xInt = x.unwrap();
    if (xInt < uMIN_WHOLE_SD59x18) {
        revert Errors.PRBMath_SD59x18_Floor_Underflow(x);
    }

    int256 remainder = xInt % uUNIT;
    if (remainder == 0) {
        result = x;
    } else {
        unchecked {
            // Solidity uses C fmod style, which returns a modulus with the same sign as x.
            int256 resultInt = xInt - remainder;
            if (xInt < 0) {
                resultInt -= uUNIT;
            }
            result = wrap(resultInt);
        }
    }
}

constructor() payable {
    bytes32 proxySalt = keccak256(abi.encode(address(this), bytes32("proxySalt")));
    address proxyAddress = address(new ERC1967Proxy{salt: proxySalt}());

    proxyHash = _extcodehash(proxyAddress);
    beaconHash = _extcodehash(address(new UpgradeableBeacon()));
    beaconProxyHash = _extcodehash(address(new ERC1967BeaconProxy()));

    if (_predictDeterministicAddressZKsync(proxyHash, proxySalt) == proxyAddress) {
        _useZKsyncCreate2Prediction = true;
    } else {
        _initCodeHashes[proxyHash] = keccak256(type(ERC1967Proxy).creationCode);
        _initCodeHashes[beaconHash] = keccak256(type(UpgradeableBeacon).creationCode);
        _initCodeHashes[beaconProxyHash] = keccak256(type(ERC1967BeaconProxy).creationCode);
    }
}
